35	
36	// ─── ツール定義（GATEWAY_SPEC.md v1.0.0）────────────────────
37	
38	const TOOLS = [
39	  {
40	    name: 'mechsense_spring_calc',
41	    description:
42	      'JIS B 2704 準拠のコイルばね（圧縮）計算。線径・コイル径・有効巻数・荷重・材料を入力し、応力・たわみ・安全判定を返す。',
43	    input_schema: {
44	      type:     'object',
45	      required: ['d', 'D', 'Na', 'P', 'mat'],
46	      properties: {
47	        d:   { type: 'number', description: '線径 (mm)' },
48	        D:   { type: 'number', description: 'コイル中心径 (mm)' },
49	        Na:  { type: 'number', description: '有効巻数' },
50	        P:   { type: 'number', description: '荷重 (N)' },
51	        mat: {
52	          type: 'string',
53	          enum: ['SW-B', 'SW-C', 'SWP-A', 'SWO-A', 'SWOSC-B', 'SUS304-WPB'],
54	          description: '材料。SW-B/SW-C=硬鋼線, SWP-A=ピアノ線, SWO-A/SWOSC-B=オイルテンパー線, SUS304-WPB=ステンレス',
55	        },
56	      },
57	    },
58	  },
59	  {
60	    name: 'mechsense_bolt_calc',
61	    description:
62	      'JIS B 1083 準拠のボルト締付計算。ボルト径・強度区分・被締結材・摩擦条件を入力し、推奨締付トルクと破損モードを返す。',
63	    input_schema: {
64	      type:     'object',
65	      required: ['d', 'grade', 'partMat', 'mu'],
66	      properties: {
67	        d:       { type: 'integer', enum: [3,4,5,6,8,10,12,16,20,22,24,27,30,33,36,39,42], description: 'ボルト呼び径 (mm)' },
68	        grade:   { type: 'string',  enum: ['4.6','4.8','8.8','10.9','12.9','A2-70','A4-70','A4-80','A2017','A5052','A6061','C3604'], description: '強度区分' },
69	        partMat: { type: 'string',  enum: ['spcc','steel','s45c','sus304','aluminum','cast_iron','brass','resin'], description: '被締結材' },
70	        mu:      { type: 'string',  enum: ['dry','lube','grease'], description: '摩擦条件。dry=乾燥(μ0.15) / lube=潤滑(μ0.10) / grease=グリス(μ0.08)' },
71	        sf:      { type: 'number',  description: '安全率（省略=1.0）' },
72	        dep:     { type: 'number',  description: 'ねじ込み深さ mm（省略=1d）' },
73	      },
74	    },
75	  },
76	  {
77	    name: 'mechsense_resonance_calc',
78	    description:
79	      'JIS B 2704 附属書準拠のコイルばね固有振動数計算。サージング共振点・第1〜4次固有振動数・システム共振・安全判定を返す。',
80	    input_schema: {
81	      type:     'object',
82	      required: ['d', 'D', 'Na', 'mat'],
83	      properties: {
84	        d:    { type: 'number', description: '線径 (mm)' },
85	        D:    { type: 'number', description: 'コイル中心径 (mm)' },
86	        Na:   { type: 'number', description: '有効巻数' },
87	        mat:  { type: 'string', enum: ['SW-B','SW-C','SWP-A','SWO-A','SWOSC-B','SUS304-WPB'], description: '材料' },
88	        rpm:  { type: 'number', description: '運転回転速度 min⁻¹（省略可）' },
89	        mass: { type: 'number', description: '搭載質量 kg（省略時はシステム共振未計算）' },
90	      },
91	    },
92	  },
93	];
94	
95	// ─── Tool executor ──────────────────────────────────────────
96	
97	const ENDPOINT_MAP = {
98	  mechsense_spring_calc:    '/api/v1/spring/calc',
99	  mechsense_bolt_calc:      '/api/v1/bolt/calc',
100	  mechsense_resonance_calc: '/api/v1/resonance/calc',
101	};
102	
103	async function executeTool(name, input) {
104	  const endpoint = ENDPOINT_MAP[name];
105	  if (!endpoint) return JSON.stringify({ error: `Unknown tool: ${name}` });
106	
107	  try {
108	    const res  = await fetch(`${API_BASE}${endpoint}`, {
109	      method:  'POST',
110	      headers: { 'Content-Type': 'application/json' },
111	      body:    JSON.stringify(input),
112	    });
113	    const data = await res.json();
114	    return JSON.stringify(data);
115	  } catch (err) {
116	    return JSON.stringify({ error: `API call failed: ${err.message}` });
117	  }
118	}
119	
120	// ─── Agentic loop ───────────────────────────────────────────
121	
122	async function query(userMessage) {
123	  const messages = [{ role: 'user', content: userMessage }];
124	
125	  while (true) {
126	    const response = await client.messages.create({
127	      model:      'claude-opus-4-7',
128	      max_tokens: 4096,
129	      system:     SYSTEM_PROMPT,
130	      tools:      TOOLS,
131	      messages,
132	    });
133	
134	    if (response.stop_reason === 'end_turn') {
135	      const textBlock = response.content.find(b => b.type === 'text');
136	      return textBlock ? textBlock.text : '';
137	    }
138	
139	    if (response.stop_reason === 'pause_turn') {
140	      messages.push({ role: 'assistant', content: response.content });
141	      continue;
142	    }
143	
144	    const toolUseBlocks = response.content.filter(b => b.type === 'tool_use');
145	    messages.push({ role: 'assistant', content: response.content });
146	
147	    const toolResults = [];
148	    for (const tool of toolUseBlocks) {
149	      const result = await executeTool(tool.name, tool.input);
150	      toolResults.push({
151	        type:        'tool_result',
152	        tool_use_id: tool.id,
153	        content:     result,
154	      });
155	    }
156	    messages.push({ role: 'user', content: toolResults });
157	  }
158	}
159	
160	// ─── CLI ────────────────────────────────────────────────────
161	
162	async function main() {
163	  const userMessage = process.argv.slice(2).join(' ');
164	  if (!userMessage) {
165	    console.error('使い方: node mechsense-agent.js "<質問>"');
166	    console.error('例: node mechsense-agent.js "d=2mm, D=15mm, Na=5巻のSW-Bばねに50N かけて大丈夫？"');
167	    process.exit(1);
168	  }
169	
170	  console.log(`質問: ${userMessage}\n`);
171	  const answer = await query(userMessage);
172	  console.log(answer);
173	}
174	
175	if (require.main === module) {
176	  main().catch(err => {
177	    console.error(err.message);
178	    process.exit(1);
179	  });
180	}
181	
182	module.exports = { query };
183

