  // Bearing モジュール（軸受特性周波数）
  // ─────────────────────────────────────────────

  /**
   * JIS 深溝玉軸受 標準寸法データベース
   * { nb: 転動体数, bd: ボール直径(mm), pd: ピッチ直径(mm), phi_deg: 接触角(°) }
   */
  const BEARING_DB = {
    '6200': { nb: 7,  bd: 4.76,  pd: 21.0,  phi_deg: 0.0 },
    '6201': { nb: 7,  bd: 5.56,  pd: 24.0,  phi_deg: 0.0 },
    '6202': { nb: 7,  bd: 6.35,  pd: 27.0,  phi_deg: 0.0 },
    '6203': { nb: 7,  bd: 6.75,  pd: 29.0,  phi_deg: 0.0 },
    '6204': { nb: 8,  bd: 7.14,  pd: 33.5,  phi_deg: 0.0 },
    '6205': { nb: 9,  bd: 7.94,  pd: 38.5,  phi_deg: 0.0 },  // CWRU検証済み
    '6206': { nb: 9,  bd: 9.52,  pd: 46.5,  phi_deg: 0.0 },
    '6207': { nb: 9,  bd: 11.11, pd: 53.5,  phi_deg: 0.0 },
    '6208': { nb: 9,  bd: 12.70, pd: 60.0,  phi_deg: 0.0 },
    '6304': { nb: 7,  bd: 9.52,  pd: 38.5,  phi_deg: 0.0 },
    '6305': { nb: 7,  bd: 11.11, pd: 44.5,  phi_deg: 0.0 },
    '6306': { nb: 8,  bd: 12.70, pd: 50.5,  phi_deg: 0.0 },
  };

  /**
   * 軸受特性周波数を計算する。
   *
   * 計算式（軸受力学の基本式）:
   *   shaft = rpm / 60                                    [Hz]
   *   ratio = (bd / pd) × cos(phi)
   *   BPFO  = (nb/2) × shaft × (1 − ratio)               外輪損傷周波数
   *   BPFI  = (nb/2) × shaft × (1 + ratio)               内輪損傷周波数
   *   BSF   = (pd / (2×bd)) × shaft × (1 − ratio²)       転動体損傷周波数
   *   FTF   = 0.5 × shaft × (1 − ratio)                  保持器損傷周波数
   *
   * @param {object} params
   * @param {string}  [params.jis]      - JIS番号（例: '6205'）。指定時は nb/bd/pd/phi_deg を自動設定
   * @param {number}  [params.nb]       - 転動体数（jis未指定時は必須）
   * @param {number}  [params.bd]       - ボール直径 (mm)
   * @param {number}  [params.pd]       - ピッチ直径 (mm)
   * @param {number}  [params.phi_deg]  - 接触角 (°)。省略時は 0
   * @param {number}   params.rpm       - 回転速度 (min⁻¹)
   * @param {number}  [params.harmonics]- 高調波次数（省略時 5）
   *
   * @returns {BearingResult}
   *   error     {string|null}  バリデーションエラー
   *   nb, bd, pd, phi_deg, rpm  {number}  入力値（jis展開後）
   *   shaft     {number}  軸周波数 (Hz)
   *   bpfo      {number}  外輪損傷周波数 (Hz)
   *   bpfi      {number}  内輪損傷周波数 (Hz)
   *   bsf       {number}  転動体損傷周波数 (Hz)
   *   ftf       {number}  保持器損傷周波数 (Hz)
   *   harmonics {object}  { bpfo, bpfi, bsf, ftf, shaft } — 各 number[] 第1〜N次
   *   warnings  {string[]}
   */
  function bearingCalc(params) {
    let { jis, nb, bd, pd, phi_deg = 0, rpm, harmonics = 5 } = params;

    const result = {
      error: null,
      jis: jis || null,
      nb: null, bd: null, pd: null, phi_deg: null, rpm: null,
      shaft: null, bpfo: null, bpfi: null, bsf: null, ftf: null,
      harmonics: null,
      warnings: [],
    };

    // JIS番号からスペック解決
    if (jis) {
      const key = String(jis).toUpperCase().replace(/\s/g, '');
      const spec = BEARING_DB[key];
      if (!spec) {
        result.error = `JIS番号 ${jis} はDBに未登録です（登録済み: ${Object.keys(BEARING_DB).join(', ')}）`;
        return result;
      }
      nb = spec.nb; bd = spec.bd; pd = spec.pd; phi_deg = spec.phi_deg;
    }

    // バリデーション
    if (!nb || isNaN(nb) || nb < 2)        { result.error = '転動体数 nb が無効です（2以上）'; return result; }
    if (!bd || isNaN(bd) || bd <= 0)       { result.error = 'ボール直径 bd が無効です'; return result; }
    if (!pd || isNaN(pd) || pd <= 0)       { result.error = 'ピッチ直径 pd が無効です'; return result; }
    if (bd >= pd)                           { result.error = 'bd < pd の条件を満たしていません'; return result; }
    if (isNaN(rpm) || rpm <= 0)            { result.error = '回転速度 rpm が無効です'; return result; }
    if (isNaN(phi_deg) || phi_deg < 0 || phi_deg >= 90) {
      result.error = '接触角 phi_deg は 0°以上 90°未満で指定してください';
      return result;
    }

    const phi   = phi_deg * Math.PI / 180;
    const ratio = (bd / pd) * Math.cos(phi);
    const shaft = rpm / 60;

    const bpfo = (nb / 2) * shaft * (1 - ratio);
    const bpfi = (nb / 2) * shaft * (1 + ratio);
    const bsf  = (pd / (2 * bd)) * shaft * (1 - ratio * ratio);
    const ftf  = 0.5 * shaft * (1 - ratio);

    const n = Math.max(1, Math.min(20, Math.round(harmonics)));
    const makeHarmonics = (f) => Array.from({ length: n }, (_, i) => f * (i + 1));

    const harmonicsResult = {
      bpfo:  makeHarmonics(bpfo),
      bpfi:  makeHarmonics(bpfi),
      bsf:   makeHarmonics(bsf),
      ftf:   makeHarmonics(ftf),
      shaft: makeHarmonics(shaft),
    };

    if (phi_deg >= 15) {
      result.warnings.push(`接触角 ${phi_deg}° — 深溝玉軸受の標準値（0°）と異なります。アンギュラ玉軸受の場合は正しい接触角を設定してください。`);
    }

    return Object.assign(result, {
      nb, bd, pd, phi_deg, rpm,
      shaft, bpfo, bpfi, bsf, ftf,
      harmonics: harmonicsResult,
    });
  }

  const Bearing = {
    /** JIS 深溝玉軸受 標準寸法データベース */
    BEARINGS: BEARING_DB,

    /**
     * 軸受特性周波数計算（BPFO / BPFI / BSF / FTF）。
     * @param {object} params - { jis?, nb?, bd?, pd?, phi_deg?, rpm, harmonics? }
     * @returns {BearingResult}
     */
    calc: bearingCalc,
  };


  // ─────────────────────────────────────────────
  // Utils — 共通ユーティリティ
  // ─────────────────────────────────────────────

  const Utils = {
    /**
     * 数値を指定桁でフォーマットする。
     * 非数・無限大・null は '—' を返す。
     * @param {number} v
     * @param {number} n - 小数桁数
